parameters.jsCode:
// Merge all data into a single payload for the AI
const invoiceResp = $('Airtable - Get Invoice Data').first().json;
const poResp = $('Airtable - Get Matching PO').first().json;
const receivingResp = $('Airtable - Get Receiving Report').first().json;
const pricesResp = $('Airtable - Get Contracted Prices').first().json;
const glResp = $('Airtable - Get GL Mapping').first().json;

const inv = invoiceResp.records[0];
const poRec = poResp.records?.[0];
const recRec = receivingResp.records?.[0];

let poLinesFormatted = 'No PO line items found';
if (poRec?.fields?.items_json) {
  try {
    const poLines = JSON.parse(poRec.fields.items_json);
    poLinesFormatted = poLines.map(l =>
      `${l.item_name} ${l.quantity} ${l.unit || ''} @ $${l.unit_price}`
    ).join('\n');
  } catch (e) {
    poLinesFormatted = poRec.fields.items_json;
  }
}

let receivingLinesFormatted = 'No receiving record found';
if (recRec?.fields?.items_received_json) {
  try {
    const recLines = JSON.parse(recRec.fields.items_received_json);
    receivingLinesFormatted = recLines.map(l =>
      `${l.item_name} ${l.qty_received} ${l.unit || ''} (ordered: ${l.qty_ordered})`
    ).join('\n');
  } catch (e) {
    receivingLinesFormatted = recRec.fields.items_received_json;
  }
}

let contractedPricesFormatted = 'No contracted prices on file';
if (pricesResp.records?.length > 0) {
  contractedPricesFormatted = pricesResp.records.map(r =>
    `${r.fields.item_name}: $${r.fields.contracted_price}/${r.fields.unit_of_measure}`
  ).join('\n');
}

let glMapping = 'No GL mapping available';
if (glResp.records?.length > 0) {
  glMapping = glResp.records.map(r => {
    const f = r.fields;
    return `${f['Item Category'] || f.item_category || 'Unknown'} → ${f['GL Code'] || f.gl_code || 'N/A'} (${f['GL Name'] || f.gl_name || 'N/A'})`;
  }).join('\n');
}

return [{
  json: {
    invoice_number: inv.fields.invoice_number,
    vendor_name: inv.fields.seller_name,
    invoice_date: inv.fields.invoice_date,
    po_reference: inv.fields.po_number,
    subtotal: inv.fields.subtotal || 0,
    tax: inv.fields.total_tax || 0,
    total: inv.fields.invoice_amount,
    currency: inv.fields.currency || 'USD',
    po_number: poRec?.fields?.po_number || inv.fields.po_number,
    po_lines_formatted: poLinesFormatted,
    po_total: poRec?.fields?.total_amount || 0,
    receiving_date: recRec?.fields?.date_received || 'N/A',
    receiving_lines_formatted: receivingLinesFormatted,
    contracted_prices_formatted: contractedPricesFormatted,
    gl_mapping: glMapping,
    invoice_record_id: inv.id,
    vendor_email: inv.fields.seller_email || ''
  }
}];

const response = $input.first().json;
const content = response.choices[0].message.content;
const parsed = JSON.parse(content.replace(/```json|```/g, '').trim());

const context = $('Code - Merge Data for AI').first().json;
return [{ json: { ...parsed, ...context } }];

