// Gather match results from the AI response node
// This runs after Slack notifications, so we pull from the upstream AI node
const data = $('Code - Parse AI Response').first().json;

const updateBody = {
  fields: {
    match_status: data.classification,
    match_details_json: JSON.stringify(data.line_results || []),
    gl_account: (data.line_results && data.line_results[0]) ? data.line_results[0].gl_code : '',
    approved: ['PERFECT_MATCH', 'MINOR_DISCREPANCY'].includes(data.classification)
  }
};

const auditBody = {
  records: [{
    fields: {
      reference_id: data.invoice_number || 'Unknown',
      event_type: 'Invoice Matched',
      actor: 'AI',
      details: (data.classification || 'Unknown') + ': ' + (data.summary || 'No summary') + ' | Variance: $' + (data.total_variance || 0),
      amount: data.total || 0
    }
  }]
};

return [{
  json: {
    invoice_record_id: data.invoice_record_id,
    update_body: JSON.stringify(updateBody),
    audit_body: JSON.stringify(auditBody)
  }
}];

